#define THREADS 256

inline int divRndUpInt(const int n, const int d) {
    return (n / d) + ((n % d) ? 1 : 0);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    const int i = (int)get_global_id(0);
    if (i < pixels) {
        const int o = i * 3;
        d_r[i] = (int)d_src[o + 0] - 128;
        d_g[i] = (int)d_src[o + 1] - 128;
        d_b[i] = (int)d_src[o + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    const int i = (int)get_global_id(0);
    if (i < pixels) {
        d_c[i] = (int)d_src[i] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) {
        return;
    }

    const int sx = sizeX;
    const int sy = sizeY;

    if (sx <= 0 || sy <= 0) {
        return;
    }

    const int llx = divRndUpInt(sx, 2);
    const int hlx = sx - llx;
    const int lly = divRndUpInt(sy, 2);
    const int hly = lly;
    const int lhy = sy - lly;
    const int hhy = lhy;

    const int offsetLL = 0;
    const int offsetHL = llx * lly;
    const int offsetLH = offsetHL + hlx * hly;
    const int offsetHH = offsetLH + llx * lhy;

    /* Horizontal forward 5/3: input -> output (temporary row-wise packed) */
    for (int y = 0; y < sy; y++) {
        const int rowIn = y * sx;
        const int rowTmp = y * sx;

        /* Predict (odd samples -> high) */
        for (int k = 0; k < hlx; k++) {
            const int idx = 2 * k + 1;
            const int left = input[rowIn + idx - 1];
            const int right = (idx + 1 < sx) ? input[rowIn + idx + 1] : left;
            const int d = input[rowIn + idx] - (left + right) / 2;
            output[rowTmp + llx + k] = d;
        }

        /* Update (even samples -> low) */
        for (int k = 0; k < llx; k++) {
            const int idx = 2 * k;
            int s = input[rowIn + idx];

            if (hlx > 0) {
                const int leftD = (k == 0) ? output[rowTmp + llx + 0]
                                           : output[rowTmp + llx + (k - 1)];
                const int rightD = (k < hlx) ? output[rowTmp + llx + k]
                                             : output[rowTmp + llx + (hlx - 1)];
                s += (leftD + rightD + 2) / 4;
            }

            output[rowTmp + k] = s;
        }
    }

    /* Vertical forward 5/3 on low-horizontal band -> LL and LH (write to input) */
    for (int x = 0; x < llx; x++) {
        /* Predict odd rows -> LH */
        for (int k = 0; k < hhy; k++) {
            const int yOdd = 2 * k + 1;
            const int left = output[(yOdd - 1) * sx + x];
            const int right = (yOdd + 1 < sy) ? output[(yOdd + 1) * sx + x] : left;
            const int d = output[yOdd * sx + x] - (left + right) / 2;
            input[offsetLH + k * llx + x] = d;
        }

        /* Update even rows -> LL */
        for (int k = 0; k < lly; k++) {
            const int yEven = 2 * k;
            int s = output[yEven * sx + x];

            if (hhy > 0) {
                const int leftD = (k == 0) ? input[offsetLH + 0 * llx + x]
                                           : input[offsetLH + (k - 1) * llx + x];
                const int rightD = (k < hhy) ? input[offsetLH + k * llx + x]
                                             : input[offsetLH + (hhy - 1) * llx + x];
                s += (leftD + rightD + 2) / 4;
            }

            input[offsetLL + k * llx + x] = s;
        }
    }

    /* Vertical forward 5/3 on high-horizontal band -> HL and HH (write to input) */
    for (int x = 0; x < hlx; x++) {
        const int col = llx + x;

        /* Predict odd rows -> HH */
        for (int k = 0; k < hhy; k++) {
            const int yOdd = 2 * k + 1;
            const int left = output[(yOdd - 1) * sx + col];
            const int right = (yOdd + 1 < sy) ? output[(yOdd + 1) * sx + col] : left;
            const int d = output[yOdd * sx + col] - (left + right) / 2;
            input[offsetHH + k * hlx + x] = d;
        }

        /* Update even rows -> HL */
        for (int k = 0; k < hly; k++) {
            const int yEven = 2 * k;
            int s = output[yEven * sx + col];

            if (hhy > 0) {
                const int leftD = (k == 0) ? input[offsetHH + 0 * hlx + x]
                                           : input[offsetHH + (k - 1) * hlx + x];
                const int rightD = (k < hhy) ? input[offsetHH + k * hlx + x]
                                             : input[offsetHH + (hhy - 1) * hlx + x];
                s += (leftD + rightD + 2) / 4;
            }

            input[offsetHL + k * hlx + x] = s;
        }
    }

    /* Copy final packed result back to output buffer */
    const int total = sx * sy;
    for (int i = 0; i < total; i++) {
        output[i] = input[i];
    }
}
